class Solution(object):
    def numberOfSpecialChars(self, word):
        last_lower = {}  # last occurrence of lowercase c
        first_upper = {}  # first occurrence of uppercase c
        for i, ch in enumerate(word):
            if ch.islower():
                last_lower[ch] = i
            else:
                c = ch.lower()
                if c not in first_upper:
                    first_upper[c] = i
        ans = 0
        for c in set(last_lower) & set(first_upper):
            if last_lower[c] < first_upper[c]:
                ans += 1
        return ans
